3	/**
4	 * Default maximum download size: 2 GiB.
5	 *
6	 * `fetch().arrayBuffer()` has ~2x peak memory overhead (undici buffers the
7	 * body internally, then creates the JS ArrayBuffer), so very large downloads
8	 * risk exceeding the default V8 heap limit on 64-bit systems and terminating
9	 * the process with an out-of-memory error.
10	 *
11	 * Setting this limit converts an unrecoverable OOM crash into a catchable
12	 * `DownloadError`.
13	 */
14	export const DEFAULT_MAX_DOWNLOAD_SIZE = 2 * 1024 * 1024 * 1024;
15	
16	/**
17	 * Reads a fetch Response body with a size limit to prevent memory exhaustion.
18	 *
19	 * Checks the Content-Length header for early rejection, then reads the body
20	 * incrementally via ReadableStream and aborts with a DownloadError when the
21	 * limit is exceeded.
22	 *
23	 * @param response - The fetch Response to read.
24	 * @param url - The URL being downloaded (used in error messages).
25	 * @param maxBytes - Maximum allowed bytes. Defaults to DEFAULT_MAX_DOWNLOAD_SIZE.
26	 * @returns A Uint8Array containing the response body.
27	 * @throws DownloadError if the response exceeds maxBytes.
28	 */
29	export async function readResponseWithSizeLimit({
30	  response,
31	  url,
32	  maxBytes = DEFAULT_MAX_DOWNLOAD_SIZE,
33	}: {
34	  response: Response;
35	  url: string;
36	  maxBytes?: number;
37	}): Promise<Uint8Array> {
38	  // Early rejection based on Content-Length header
39	  const contentLength = response.headers.get('content-length');
40	  if (contentLength != null) {
41	    const length = parseInt(contentLength, 10);
42	    if (!isNaN(length) && length > maxBytes) {
43	      throw new DownloadError({
44	        url,
45	        message: `Download of ${url} exceeded maximum size of ${maxBytes} bytes (Content-Length: ${length}).`,
46	      });
47	    }
48	  }
49	
50	  const body = response.body;
51	
52	  // Handle missing body (empty responses)
53	  if (body == null) {
54	    return new Uint8Array(0);
55	  }
56	
57	  const reader = body.getReader();
58	  const chunks: Uint8Array[] = [];
59	  let totalBytes = 0;
60	
61	  try {
62	    while (true) {
63	      const { done, value } = await reader.read();
64	
65	      if (done) {
66	        break;
67	      }
68	
69	      totalBytes += value.length;
70	
71	      if (totalBytes > maxBytes) {
72	        throw new DownloadError({
73	          url,
74	          message: `Download of ${url} exceeded maximum size of ${maxBytes} bytes.`,
75	        });
76	      }
77	
78	      chunks.push(value);
79	    }
80	  } finally {
81	    try {
82	      await reader.cancel();
83	    } finally {
84	      reader.releaseLock();
85	    }
86	  }
87	
88	  // Concatenate chunks into a single Uint8Array
89	  const result = new Uint8Array(totalBytes);
90	  let offset = 0;
91	  for (const chunk of chunks) {
92	    result.set(chunk, offset);
93	    offset += chunk.length;
94	  }
95	
96	  return result;
97	}
