      "require": "./dist/index.js"
    },
    "./internal": {
      "types": "./dist/internal/index.d.ts",
      "import": "./dist/internal/index.mjs",
      "module": "./dist/internal/index.mjs",
      "require": "./dist/internal/index.js"
    }
  },
  "dependencies": {
    "@ai-sdk/provider": "workspace:*",
    "@ai-sdk/provider-utils": "workspace:*"
  },
  "devDependencies": {
    "@ai-sdk/test-server": "workspace:*",
    "@types/node": "20.17.24",
    "@vercel/ai-tsconfig": "workspace:*",
    "tsup": "^8",
    "typescript": "5.8.3",
    "zod": "3.25.76"
  },
  "peerDependencies": {
    "zod": "^3.25.76 || ^4.1.8"
  },
  "engines": {
    "node": ">=18"
  },
  "publishConfig": {
    "access": "public"
  },
  "homepage": "https://ai-sdk.dev/docs",
  "repository": {
    "type": "git",
    "url": "git+https://github.com/vercel/ai.git"
  },
  "bugs": {
    "url": "https://github.com/vercel/ai/issues"
  },
  "keywords": ["ai"]
}
```

**Key differences**:
- Mistral doesn't include `internal.d.ts` in files (simpler provider)
- OpenAI and Anthropic have `internal` export and `internal.d.ts`
- Simpler providers (Mistral) use single tsup entry; complex ones (OpenAI) have dual entries

---

### 3. **TSUP.CONFIG.TS - BUILD CONFIGURATION**

**Simple provider pattern** (Mistral):
```typescript
import { defineConfig } from 'tsup';

export default defineConfig([
  {
    entry: ['src/index.ts'],
    format: ['cjs', 'esm'],
    dts: true,
    sourcemap: true,
    define: {
      __PACKAGE_VERSION__: JSON.stringify(
        (await import('./package.json', { with: { type: 'json' } })).default
          .version,
      ),
    },
  },
]);
```

**Complex provider pattern** (OpenAI with internal exports):
```typescript
import { defineConfig } from 'tsup';

export default defineConfig([
  {
    entry: ['src/index.ts'],
    format: ['cjs', 'esm'],
    dts: true,
    sourcemap: true,
    define: {
      __PACKAGE_VERSION__: JSON.stringify(
        (await import('./package.json', { with: { type: 'json' } })).default
          .version,
      ),
    },
  },
  {
    entry: ['src/internal/index.ts'],
    outDir: 'dist/internal',
    format: ['cjs', 'esm'],
    dts: true,
    sourcemap: true,
    define: {
      __PACKAGE_VERSION__: JSON.stringify(
        (await import('./package.json', { with: { type: 'json' } })).default
          .version,
      ),
    },
  },
]);
```

---

### 4. **WHAT TO EXPORT FROM INDEX.TS**

**Pattern from Mistral** (simplest pattern):
```typescript
export { createMistral, mistral } from './mistral-provider';
export type {
  MistralProvider,
  MistralProviderSettings,
} from './mistral-provider';
export type { MistralLanguageModelOptions } from './mistral-chat-options';
export { VERSION } from './version';
```

**Pattern from Anthropic** (more complete):
```typescript
export type {
  AnthropicMessageMetadata,
  AnthropicUsageIteration,
} from './anthropic-message-metadata';
export type {
  AnthropicLanguageModelOptions,
  /** @deprecated Use `AnthropicLanguageModelOptions` instead. */
  AnthropicLanguageModelOptions as AnthropicProviderOptions,
} from './anthropic-messages-options';
export type { AnthropicToolOptions } from './anthropic-prepare-tools';
export { anthropic, createAnthropic } from './anthropic-provider';
export type {
  AnthropicProvider,
  AnthropicProviderSettings,
} from './anthropic-provider';
export { forwardAnthropicContainerIdFromLastStep } from './forward-anthropic-container-id-from-last-step';
export { VERSION } from './version';
```

**Export naming conventions** (from contributing/providers.md):
- Types are PascalCase: `AnthropicLanguageModelOptions`
- Provider types: `{Provider}Provider`, `{Provider}ProviderSettings`
- Model options: `{Provider}{ModelType}Options` (e.g., `MistralLanguageModelOptions`)
- For multiple implementations: `{Provider}{ModelType}{Qualifier}Options` (e.g., `OpenAILanguageModelChatOptions`)
- Zod schemas are NOT exported, only types
- All types must be exported from the provider package

---

### 5. **PROVIDER-UTILS KEY UTILITIES FOR IMAGE GENERATION**

From `/packages/provider-utils/src/index.ts`, key utilities used by image providers:

**Image file conversion**:
```typescript
export { convertImageModelFileToDataUri } from './convert-image-model-file-to-data-uri';
```
Converts `ImageModelV3File` (URL or base64 or Uint8Array) to data URI string.

**Download utilities**:
```typescript
export { downloadBlob } from './download-blob';
export { DownloadError } from './download-error';
export { readResponseWithSizeLimit, DEFAULT_MAX_DOWNLOAD_SIZE } from './read-response-with-size-limit';
```
- `downloadBlob(url, options?)`: Downloads from URL with SSRF validation and size limits (default 2 GiB)
- `readResponseWithSizeLimit(response, url, maxBytes)`: Incremental streaming read with protection
- Default max: 2 GiB to prevent OOM crashes

**Form data conversion**:
```typescript
export { convertToFormData } from './convert-to-form-data';
```
Used by OpenAI for image edit endpoints.

**Base64 conversion**:
```typescript
export { convertBase64ToUint8Array } from './uint8-utils';
```

**API helpers**:
```typescript
export { postJsonToApi, postFormDataToApi } from '...';
export { combineHeaders } from './combine-headers';
export { createJsonResponseHandler } from './response-handler';
```

**Full list of all exported utilities** (66 total):
- combine-headers
- convertAsyncIteratorToReadableStream
- createToolNameMapping, ToolNameMapping
- delay
- DelayedPromise
- extractResponseHeaders
- convertImageModelFileToDataUri
- convertToFormData
- downloadBlob
- DownloadError
- readResponseWithSizeLimit, DEFAULT_MAX_DOWNLOAD_SIZE
- fetchFunction
- createIdGenerator, generateId, IdGenerator
- getErrorMessage
- getFromApi
- getRuntimeEnvironmentUserAgent
- injectJsonInstructionIntoMessages
- isAbortError
- isNonNullable
- isUrlSupported
- loadApiKey
- loadOptionalSetting
- loadSetting
- MaybePromiseLike
- mediaTypeToExtension
- normalizeHeaders
- parseJson
- parseJsonEventStream
- parseProviderOptions
- postToApi
- createProviderToolFactory
- removeUndefinedEntries
- resolve
- responseHandler
- schema utilities (asSchema, jsonSchema, lazySchema, zodSchema, Schema types)
- stripFileExtension
- uint8-utils
- validateDownloadUrl
- validateTypes
- VERSION
- withUserAgentSuffix
- withoutTrailingSlash

---

### 6. **PROVIDER INTERFACE IMPLEMENTATIONS**

**Minimal required provider structure** (from provider/src/index.ts):

A provider must implement one or more:
- `LanguageModelV3` - text generation
- `ImageModelV3` - image generation
- `EmbeddingModelV3` - embeddings
- `SpeechModelV3` - speech synthesis
- `TranscriptionModelV3` - speech-to-text
- `VideoModelV3` - video generation
- `RerankingModelV3` - ranking

**Provider factory pattern**:
```typescript
export interface MistralProvider extends ProviderV3 {
  (modelId: MistralChatModelId): LanguageModelV3;
  languageModel(modelId: MistralChatModelId): LanguageModelV3;
  embedding(modelId: MistralEmbeddingModelId): EmbeddingModelV3;
}

export interface MistralProviderSettings {
  baseURL?: string;
  apiKey?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
  generateId?: () => string;
}

export function createMistral(
  options: MistralProviderSettings = {},
): MistralProvider {
  // Implementation
}

export const mistral = createMistral();
```

---

### 7. **LANGUAGE MODEL V3 IMPLEMENTATION PATTERN**

From `mistral-chat-language-model.ts`:

```typescript
import { LanguageModelV3, ... } from '@ai-sdk/provider';
import { ... } from '@ai-sdk/provider-utils';

type MistralChatConfig = {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  generateId?: () => string;
