    this.modelId = modelId;
    this.config = config;
    this.generateId = config.generateId ?? generateId;
  }

  get provider(): string {
    return this.config.provider;
  }

  readonly supportedUrls: Record<string, RegExp[]> = {
    'application/pdf': [/^https:\/\/.*$/],
  };

  private async getArgs(options: LanguageModelV3CallOptions) {
    const warnings: SharedV3Warning[] = [];
    // Implementation
  }

  async doGenerate(options: LanguageModelV3CallOptions): Promise<LanguageModelV3GenerateResult> {
    // Use postJsonToApi, createJsonResponseHandler, etc.
  }

  async doStream(options: LanguageModelV3CallOptions): Promise<LanguageModelV3StreamResult> {
    // Use createEventSourceResponseHandler
  }
}
```

---

### 8. **FILE STRUCTURE BY PROVIDER TYPE**

**Mistral** (simplest, ~18 files):
```
src/
├── index.ts (7 exports)
├── mistral-provider.ts (ProviderV3 + ProviderSettings)
├── mistral-chat-language-model.ts (LanguageModelV3 impl)
├── mistral-embedding-model.ts (EmbeddingModelV3 impl)
├── mistral-chat-options.ts (type defs + zod schemas)
├── mistral-chat-prompt.ts (prompt formatting)
├── mistral-embedding-options.ts (embedding options)
├── convert-to-mistral-chat-messages.ts (prompt conversion)
├── convert-mistral-usage.ts (token counting)
├── mistral-error.ts (error handling)
├── mistral-prepare-tools.ts (tool handling)
├── map-mistral-finish-reason.ts (finish reason mapping)
├── get-response-metadata.ts
├── version.ts
├── *.test.ts files
```

**OpenAI** (complex, includes image gen):
- Language models (chat, completion, assistants)
- Image models (generation, editing)
- All the conversion/mapping utilities above
- Plus: internal.ts with private APIs

**Anthropic** (complex with tools):
- Language model with extended tool support
- Message metadata handling
- Container ID forwarding for compute
- Tool search integration

---

### 9. **DEPENDENCIES REQUIREMENTS**

**All provider packages require**:
```json
"dependencies": {
  "@ai-sdk/provider": "workspace:*",
  "@ai-sdk/provider-utils": "workspace:*"
}
```

**Peer dependency** (zod validation):
```json
"peerDependencies": {
  "zod": "^3.25.76 || ^4.1.8"
}
```

**No peer dependency on actual provider SDK** - providers handle their own imports internally. This keeps the SDK modular.

---

### 10. **CONTRIBUTING GUIDE REQUIREMENTS**

From `/contributing/add-new-provider.md`:

Steps:
1. Create folder `packages/<provider>`
2. Set version in `package.json` to `0.0.0`
3. Create changeset for new package with `major`
4. Add examples to `examples/ai-functions/src/*/<provider>.ts`
5. Add documentation in `content/providers/01-ai-sdk-providers/<next-number>-<provider>.mdx`

From `/contributing/providers.md`:
- **Options schemas**: Use `.optional()` unless `null` is meaningful
- **Response schemas**: Use `.nullish()` for flexibility
- **Type naming**: PascalCase for types, camelCase for Zod schemas
- **Export rule**: Types exported, Zod schemas NOT exported
- **Method names**: Use "Model" suffix in ProviderV3 (e.g., `languageModel(id)`, not just `language(id)`)

---

### 11. **SUMMARY TABLE**

| Aspect | Pattern | Notes |
|--------|---------|-------|
| **Package name** | `@ai-sdk/<provider>` | Public npm scope |
| **Version** | `3.0.X` | Start at `3.0.0` per contributing guide |
| **Dependencies** | `@ai-sdk/provider`, `@ai-sdk/provider-utils` | Workspace only |
| **Dev dependencies** | `tsup`, `typescript`, `zod`, `vitest` | Standard stack |
| **Build tool** | tsup with 2 entries (main + internal optional) | Generates CJS + ESM |
| **tsconfig** | Extends shared, references provider + utils | Composite builds |
| **Exports** | Main + optional internal export | Dual exports for advanced cases |
| **Model implementations** | LanguageModelV3, ImageModelV3, EmbeddingModelV3, etc. | One class per model type |
| **Utilities** | downloadBlob, convertImageModelFileToDataUri, postJsonToApi | From provider-utils |
| **Testing** | vitest with node + edge configs | Split browser/server |

This comprehensive structure allows the Vercel AI SDK to maintain consistency across 50+ provider packages while supporting different complexity levels from simple (Mistral) to complex (OpenAI, Anthropic).

