// Known PixelArt image model IDs
export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-v2'
  | (string & {});

/**
 * Provider-specific settings for PixelArt image generation.
 * Passed via providerOptions: { pixelart: { style: 'pixel', pixelDensity: 8 } }
 */
export interface PixelArtImageSettings {
  /**
   * The artistic style for the generated image.
   * - 'pixel': Classic pixel art style
   * - 'retro': Retro 16-bit style
   * - '8bit': Classic 8-bit video game style
   */
  style?: 'pixel' | 'retro' | '8bit';

