### Step 8 — `packages/pixelart/src/pixelart-image-model.ts`

Implements `ImageModelV3` from `@ai-sdk/provider`. Uses `postJsonToApi`, `createJsonResponseHandler`, `createJsonErrorResponseHandler`, `combineHeaders`, and `parseProviderOptions` from `@ai-sdk/provider-utils`. Uses Zod v4 for schema validation (matching the `z from 'zod/v4'` pattern used in TogetherAI).

Key implementation notes:
- `maxImagesPerCall = 1` (PixelArt API generates one at a time)
- `size` from call options is forwarded directly as a string (e.g. `"512x512"`)
- `style` and `pixelDensity` are extracted from `providerOptions.pixelart` via `parseProviderOptions` + Zod schema
- `aspectRatio` is not supported → emit an `'unsupported'` warning
- `seed` is forwarded if provided
- Response returns `b64_json` base64 strings

```typescript
import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  FetchFunction,
  InferSchema,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { PixelArtImageModelId } from './pixelart-image-settings';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  _internal?: { currentDate?: () => Date };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string { return this.config.provider; }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt, n, size, aspectRatio, seed,
    providerOptions, headers, abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];
    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: 'PixelArt does not support aspectRatio. Use `size` (e.g. "512x512") instead.',
      });
    }

    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        ...(size != null ? { size } : {}),
        ...(seed != null ? { seed } : {}),
        response_format: 'b64_json',
        ...(pixelartOptions ?? {}),
      },
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelArtErrorSchema,
        errorToMessage: data => data.error.message,
      }),
      successfulResponseHandler: createJsonResponseHandler(pixelArtImageResponseSchema),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

// Response schema — minimal, focused on what's needed
const pixelArtImageResponseSchema = z.object({
  data: z.array(z.object({ b64_json: z.string() })),
});

const pixelArtErrorSchema = z.object({
  error: z.object({ message: z.string() }),
});

// Provider options schema for PixelArt image generation
export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      style: z.enum(['pixel', 'retro', '8bit']).nullish(),
      pixelDensity: z.number().nullish(),
    }).passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<typeof pixelArtImageModelOptionsSchema>;
```

---

### Step 9 — `packages/pixelart/src/pixelart-provider.ts`

Defines `PixelArtProvider` interface (extends `ProviderV3`), `PixelArtProviderSettings`, and the `createPixelArt` factory function. Also exports a default `pixelart` instance.

```typescript
import { ImageModelV3, ProviderV3 } from '@ai-sdk/provider';
import {
  FetchFunction,
  loadApiKey,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

export interface PixelArtProviderSettings {
  /** PixelArt API key. Defaults to PIXELART_API_KEY env var. */
  apiKey?: string;
  /** Base URL for API calls. Defaults to https://api.pixelart.ai/v1 */
  baseURL?: string;
  /** Additional headers included in every request. */
  headers?: Record<string, string>;
  /** Custom fetch implementation (e.g. for testing). */
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  /** Creates an image generation model. */
  image(modelId: PixelArtImageModelId): ImageModelV3;
  /** Creates an image generation model (canonical method name). */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL = withoutTrailingSlash(
    options.baseURL ?? 'https://api.pixelart.ai/v1',
  );

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const provider = function (modelId: PixelArtImageModelId) {
    return createImageModel(modelId);
  } as PixelArtProvider;

  provider.specificationVersion = 'v3';
  provider.image = createImageModel;
  provider.imageModel = createImageModel;

  return provider;
}

export const pixelart = createPixelArt();
```

