### Step 7 — `packages/pixelart/src/pixelart-image-settings.ts`

Defines the model ID type and the provider-specific settings interface. `size` is handled as a standard `ImageModelV3CallOptions` parameter (`` `${number}x${number}` ``); `style` and `pixelDensity` are provider-specific options passed via `providerOptions.pixelart`.

```typescript
// Known PixelArt image model IDs
export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-v2'
  | (string & {});

/**
 * Provider-specific settings for PixelArt image generation.
 * Passed via providerOptions: { pixelart: { style: 'pixel', pixelDensity: 8 } }
 */
export interface PixelArtImageSettings {
  /**
   * The artistic style for the generated image.
   * - 'pixel': Classic pixel art style
   * - 'retro': Retro 16-bit style
   * - '8bit': Classic 8-bit video game style
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * The pixel density (pixels per unit) for the image.
   * Higher values produce finer pixel detail.
   */
  pixelDensity?: number;
