import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  FetchFunction,
  postJsonToApi,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModelId, PixelArtImageSettings } from './pixelart-image-settings';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

// Response schema definitions for JSON parsing (inline type-only validation)
interface PixelArtImageResponse {
  data: Array<{ b64_json: string }>;
}

interface PixelArtErrorResponse {
  error: { message: string };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];
    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio. Use `size` (e.g. "512x512") instead.',
      });
    }

    // Extract PixelArt-specific provider options
    const pixelartOptions = (providerOptions?.pixelart ??
      {}) as PixelArtImageSettings;

    // https://api.pixelart.ai/v1/images/generations
    const { value: response, responseHeaders } = await postJsonToApi<
      PixelArtImageResponse
    >({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        ...(size != null ? { size } : {}),
        ...(seed != null ? { seed } : {}),
        response_format: 'b64_json',
        ...(pixelartOptions.style != null
          ? { style: pixelartOptions.style }
          : {}),
        ...(pixelartOptions.pixelDensity != null
          ? { pixel_density: pixelartOptions.pixelDensity }
          : {}),
      },
      failedResponseHandler: createJsonErrorResponseHandler<PixelArtErrorResponse>(
        {
          errorSchema: {
            parse: (data: unknown) => {
              const d = data as PixelArtErrorResponse;
              return { success: true as const, value: d };
            },
          } as Parameters<typeof createJsonErrorResponseHandler>[0]['errorSchema'],
          errorToMessage: (data: PixelArtErrorResponse) => data.error.message,
        },
      ),
      successfulResponseHandler: createJsonResponseHandler<PixelArtImageResponse>(
        {
          parse: (data: unknown) => {
            const d = data as PixelArtImageResponse;
            return { success: true as const, value: d };
          },
        } as Parameters<typeof createJsonResponseHandler>[0],
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

